const dayOptions = [{ value: 1, label: 'Mon' }, { value: 2, label: 'Tue' }, { value: 3, label: 'Wed' }, { value: 4, label: 'Thu' }, { value: 5, label: 'Fri' }, { value: 6, label: 'Sat' }, { value: 0, label: 'Sun' }];
const customerSegmentOptions = ['all', 'wallet customers', 'new customers', 'existing customers', 'Regular', 'VIP', 'Wholesale', 'Corporate', 'Staff'];
const channelOptions = [{ value: 'cafe_billing', label: 'Cafe billing' }, { value: 'branch_billing', label: 'Branch billing' }];
const today = () => new Date().toISOString().slice(0, 10);
const addDays = (days: number) => { const date = new Date(); date.setDate(date.getDate() + days); return date.toISOString().slice(0, 10); };
const parseList = (value: string) => Array.from(new Set(value.split(/[\n,]+/).map((item) => item.trim()).filter(Boolean)));
const joinList = (value?: string[]) => (value || []).join(', ');
const ruleLabel = (value?: PromotionRuleType) => ruleTypes.find((item) => item.value === value)?.label || 'Promotion';
const dateText = (value: string) => new Date(`${value}T00:00:00`).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
const escapeHtml = (value: unknown) => String(value ?? '').replace(/[&<>'"]/g, (character) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;' }[character] || character));

function Modal({ title, subtitle, onClose, children, wide = false }: { title: string; subtitle: string; onClose: () => void; children: React.ReactNode; wide?: boolean }) {
  return <div className="fixed inset-0 z-[80] flex items-center justify-center bg-slate-950/60 p-3" onMouseDown={onClose}><div className={`max-h-[95vh] w-full ${wide ? 'max-w-6xl' : 'max-w-4xl'} overflow-hidden rounded-3xl bg-white shadow-2xl`} onMouseDown={(event) => event.stopPropagation()}><div className="flex items-start justify-between border-b px-5 py-4"><div><h3 className="font-display text-xl font-black">{title}</h3><p className="text-xs text-slate-500">{subtitle}</p></div><button onClick={onClose} className="rounded-xl bg-slate-100 p-2" aria-label="Close"><X className="size-4" /></button></div><div className="max-h-[calc(95vh-82px)] overflow-y-auto p-5">{children}</div></div></div>;
}

function Kpi({ label, value, icon, note }: { label: string; value: string; icon: React.ReactNode; note?: string }) {
  return <div className="rounded-3xl border border-slate-200 bg-white p-4 shadow-sm"><div className="flex items-start justify-between gap-3"><div><p className="text-[10px] font-black uppercase tracking-[.15em] text-slate-500">{label}</p><p className="mt-2 font-display text-2xl font-black text-slate-950">{value}</p>{note && <p className="mt-1 text-[11px] text-slate-500">{note}</p>}</div><div className="rounded-2xl bg-purple-50 p-2.5 text-purple-700">{icon}</div></div></div>;
}

function csv(filename: string, rows: Array<Record<string, string | number>>) {
  const safe = rows.length ? rows : [{ Status: 'No data' }]; const headers = Object.keys(safe[0]);
  const content = [headers.join(','), ...safe.map((row) => headers.map((key) => `"${String(row[key] ?? '').replace(/"/g, '""')}"`).join(','))].join('\n');
  const url = URL.createObjectURL(new Blob([content], { type: 'text/csv;charset=utf-8' })); const a = document.createElement('a'); a.href = url; a.download = filename; a.click(); URL.revokeObjectURL(url);
}

